CREATE VIEW `ads_watch_user_video3log_view` (`dt` COMMENT "createtime 分区", `product_id` COMMENT "产品id", `id` COMMENT "自增id", `mt` COMMENT "终端", `core` COMMENT "corever", `unique_cdreader_id` COMMENT "唯一设备识别id", `position` COMMENT "位置", `user_id` COMMENT "用户id", `create_tm` COMMENT "创建时间", `app_id` COMMENT "应用程序id", `etl_tm` COMMENT "时间")
COMMENT "观看激励视频记录表" AS SELECT `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`dt`, `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`product_id`, `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`Id`, `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`Mt`, `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`Core`, `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`UniqueCdReaderId` AS `unique_cdreader_id`, `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`Position`, `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`UserId` AS `user_id`, `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`CreateTime` AS `create_tm`, `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`.`AppId` AS `app_id`, now() AS `etl_tm`
FROM `ods_log`.`ods_tidb_readerlog_Log_UserWatchVideo3Log`;